    text-align:center}
</style>
</head>
<body>
<div class="wrap">
  <header class="nav">
    <div class="brand"><span class="dot"></span> WASTEDTOKEN MINT</div>
    <small>Physical challenge coins · On-chain provenance</small>
  </header>

  <div class="hero">
    <h1>The coin that proves you were there.</h1>
    <p>WastedToken Mint forges heavyweight collectible challenge coins — embossed,
       reeded, and numbered. One loop. Both faces. Pure metal.</p>
    <canvas id="coin-hero"></canvas>
    <div class="loop-note">Live render · rotates &amp; flips · specular rakes as it turns</div>
  </div>

  <section class="block about">
    <h2 class="section">About the mint</h2>
    <p>We are a small, obsessive workshop that believes digital clout deserves a
       physical artifact. Every WastedToken coin is struck from solid metal,
       individually finished, and shipped with a tamper-evident seal. The front
       carries our emblem in deep relief; the back carries your token denomination,
       laser-verified against the chain. No two patinas age the same.</p>
    <div class="stats">
      <div class="stat"><b>4</b><span>editions released</span></div>
      <div class="stat"><b>42g</b><span>avg coin weight</span></div>
      <div class="stat"><b>100%</b><span>hand-finished edge</span></div>
      <div class="stat"><b>0</b><span>placeholder discs</span></div>
    </div>
  </section>

  <section class="block">
    <h2 class="section">The collection</h2>
    <div class="grid">
      <div class="edition" data-edition="bronze" data-state="available">
        <canvas class="edition-canvas"></canvas>
        <h3>Bronze</h3>
        <div class="meta">10,000 TOKENS · available now</div>
        <div class="state available">AVAILABLE</div>
        <button class="buy">Add to cart</button>
      </div>
      <div class="edition" data-edition="silver" data-state="available">
        <canvas class="edition-canvas"></canvas>
        <h3>Silver</h3>
        <div class="meta">25,000 TOKENS · available now</div>
        <div class="state available">AVAILABLE</div>
        <button class="buy">Add to cart</button>
      </div>
      <div class="edition" data-edition="gold" data-state="sold-out">
        <canvas class="edition-canvas"></canvas>
        <h3>Gold</h3>
        <div class="meta">100,000 TOKENS · limited strike</div>
        <div class="state sold-out">SOLD OUT</div>
      </div>
      <div class="edition" data-edition="black" data-state="coming-soon">
        <canvas class="edition-canvas"></canvas>
        <h3>Black (Obsidian)</h3>
        <div class="meta">250,000 TOKENS · anodized</div>
        <div class="state coming-soon">MINTING NEXT SEASON: WINTER</div>
      </div>
    </div>
  </section>

  <footer>
    WastedToken Mint — struck for the troll kingdom. All coins are physical.
    Not financial advice. Do not eat the coin.
  </footer>
</div>

<script>
/* ============================================================
   Procedural coin renderer (2D canvas, fake-3D + lighting)
   ============================================================ */
function makeCoinRenderer(canvas, opts){
  opts = opts || {};
  const ctx = canvas.getContext('2d');
  const DPR = Math.min(window.devicePixelRatio||1, 2);

  function resize(){
    const r = canvas.getBoundingClientRect();
    const w = Math.max(40, r.width|0), h = Math.max(40, r.height|0);
    canvas.width = w*DPR; canvas.height = h*DPR;
    ctx.setTransform(DPR,0,0,DPR,0,0);
    return {w,h};
  }

  // metal palette
  const metals = {
    bronze:{base:[150,86,46], hi:[255,190,130], lo:[60,28,12], edge:[90,46,22]},
    silver:{base:[190,200,215], hi:[255,255,255], lo:[90,98,115], edge:[140,148,165]},
    gold:{base:[214,170,70], hi:[255,240,180], lo:[120,86,20], edge:[160,120,40]},
    black:{base:[40,43,52], hi:[150,160,180], lo:[10,11,15], edge:[30,32,40]}
  };
  const metal = metals[opts.metal||'gold'];

  function draw(t){
    const {w,h} = resize();
    ctx.clearRect(0,0,w,h);

    const cx = w/2, cy = h/2;
    const R = Math.min(w,h)*0.36;           // coin radius (never touches edge)
    // loop: rotate about vertical (yaw) and flip about horizontal (pitch)
    const yaw = t*Math.PI*2;
    const pitch = Math.sin(t*Math.PI*2)*Math.PI*0.5; // -90..90 flip
    const cosY = Math.cos(yaw), sinY = Math.sin(yaw);
    const cosP = Math.cos(pitch), sinP = Math.sin(pitch);

    // which face is toward viewer? front if cosP>0 else back
    const showFront = cosP >= 0;
    const faceSign = showFront ? 1 : -1;

    // 3D normal of disc center (after yaw then pitch)
    // disc local normal = (0,0,1)
    // yaw: (sinY,0,cosY)
    // pitch around X: (x, y*cosP - z*sinP, y*sinP + z*cosP)
    let nx = sinY;
    let ny = 0*cosP - cosY*sinP;
    let nz = 0*sinP + cosY*cosP;
    // light direction (raking)
    const lx = Math.cos(t*Math.PI*2 - 0.6);
    const ly = -0.25;
    const lz = 0.92;
    let diff = nx*lx + ny*ly + nz*lz;
    diff = Math.max(0, Math.min(1, diff));
    // specular
    const vx=0,vy=0,vz=1;
    const rx = 2*diff*nx - lx, ry = 2*diff*ny - ly, rz = 2*diff*nz - lz;
    let spec = Math.max(0, rx*vx+ry*vy+rz*vz);
    spec = Math.pow(spec, 22);

    // edge (reeded) — draw as ellipse band using projected radius
    const Rx = R*Math.abs(cosY);   // horizontal squash from yaw
    const Ry = R*Math.abs(cosP);   // vertical squash from pitch
    // thickness
    const thick = R*0.10;
    const ty = Math.sin(pitch)*thick; // vertical shift of back face

    // edge band
    ctx.save();
    ctx.translate(cx, cy);
    const eg = ctx.createLinearGradient(-Rx,-Ry,Rx,Ry);
    eg.addColorStop(0, rgb(metal.edge, 0.5+0.5*diff));
    eg.addColorStop(0.5, rgb(metal.lo,1));
    eg.addColorStop(1, rgb(metal.edge, 0.4+0.6*diff));
    // reeded lines
    ctx.beginPath();
    ctx.ellipse(0, ty/2, Rx, Ry+Math.abs(ty)/2, 0, 0, Math.PI*2);
    ctx.fillStyle = eg; ctx.fill();
    // ridges
    const ridges = 60;
    for(let i=0;i<ridges;i++){
      const a = (i/ridges)*Math.PI*2;
      const ex = Math.cos(a)*Rx;
      const ey = Math.sin(a)*(Ry+Math.abs(ty)/2) + ty/2;
      const ex2 = Math.cos(a)*Rx;
      const ey2 = Math.sin(a)*(Ry-Math.abs(ty)/2) - ty/2;
      ctx.strokeStyle = (i%2? 'rgba(255,255,255,0.10)':'rgba(0,0,0,0.25)');
      ctx.lineWidth = 1;
      ctx.beginPath(); ctx.moveTo(ex,ey); ctx.lineTo(ex2,ey2); ctx.stroke();
    }
    ctx.restore();

    // face disc
    ctx.save();
    ctx.translate(cx, cy - ty/2);
    const fg = ctx.createRadialGradient(-Rx*0.3, -Ry*0.3, R*0.1, 0,0, R);
    const baseC = mix(metal.base, metal.hi, diff*0.6);
    fg.addColorStop(0, rgb(mix(baseC, metal.hi, spec),1));
    fg.addColorStop(0.6, rgb(baseC,1));
    fg.addColorStop(1, rgb(metal.lo,1));
    ctx.beginPath();
    ctx.ellipse(0,0,Rx,Ry,0,0,Math.PI*2);
    ctx.fillStyle = fg; ctx.fill();

    // inner ring
    ctx.lineWidth = Math.max(2, R*0.04);
    ctx.strokeStyle = rgb(metal.lo,0.8);
    ctx.beginPath(); ctx.ellipse(0,0,Rx*0.82,Ry*0.82,0,0,Math.PI*2); ctx.stroke();

    // emboss content
    ctx.save();
    ctx.scale(Rx/R, Ry/R); // map circle->ellipse
    ctx.translate(0,0);
    if(showFront){
      drawEmblem(ctx, R, metal, diff, spec);
    } else {
      drawDenom(ctx, R, metal, diff, spec, opts.denom||'10,000 TOKENS');
    }
    ctx.restore();

    // moving specular hotspot (rakes across)
    const hx = -Rx*0.5 + (t*2%1)*Rx*1.0;
    const hy = -Ry*0.2;
    const sg = ctx.createRadialGradient(hx,hy,0,hx,hy,R*0.6);
    sg.addColorStop(0,'rgba(255,255,255,'+(0.35*spec+0.15)+')');
    sg.addColorStop(1,'rgba(255,255,255,0)');
    ctx.beginPath(); ctx.ellipse(0,0,Rx,Ry,0,0,Math.PI*2);
    ctx.fillStyle = sg; ctx.fill();

    ctx.restore();
  }

  function drawEmblem(c, R, metal, diff, spec){
    c.save();
    c.fillStyle = rgb(mix(metal.lo, metal.base, 0.4), 1);
    c.strokeStyle = rgb(mix(metal.hi, [255,255,255], spec*0.5), 0.9);
    c.lineWidth = R*0.03;
    // emblem: shield + bolt
    c.beginPath();
    c.moveTo(0,-R*0.5);
    c.lineTo(R*0.34,-R*0.28);
    c.lineTo(R*0.30,R*0.18);
    c.lineTo(0,R*0.5);
    c.lineTo(-R*0.30,R*0.18);
    c.lineTo(-R*0.34,-R*0.28);
    c.closePath();
    c.fill(); c.stroke();
    // bolt
    c.beginPath();
    c.moveTo(R*0.05,-R*0.22);
    c.lineTo(-R*0.12,R*0.04);
    c.lineTo(R*0.02,R*0.04);
    c.lineTo(-R*0.05,R*0.26);
    c.lineTo(R*0.14,-R*0.04);
    c.lineTo(R*0.0,-R*0.04);
    c.closePath();
    c.fillStyle = rgb(mix(metal.hi,[255,255,255],spec),1);
    c.fill();
    // text arc
    c.fillStyle = rgb(mix(metal.lo,[0,0,0],0.2),1);
    c.font = '700 '+(R*0.12)+'px ui-sans-serif,system-ui,sans-serif';
    c.textAlign='center'; c.textBaseline='middle';
    c.fillText('WASTED', 0, -R*0.66);
    c.fillText('MINT', 0, R*0.66);
    c.restore();
  }

  function drawDenom(c, R, metal, diff, spec, text){
    c.save();
    c.fillStyle = rgb(mix(metal.hi,[255,255,255],spec*0.4),1);
    c.font = '800 '+(R*0.20)+'px ui-sans-serif,system-ui,sans-serif';
    c.textAlign='center'; c.textBaseline='middle';
    const parts = text.split(' ');
    c.fillText(parts[0], 0, -R*0.08);
    c.font = '700 '+(R*0.11)+'px ui-sans-serif,system-ui,sans-serif';
    c.fillText(parts.slice(1).join(' '), 0, R*0.20);
    // small mark
    c.beginPath(); c.arc(0,-R*0.42,R*0.05,0,Math.PI*2);
    c.fillStyle = rgb(metal.lo,1); c.fill();
    c.restore();
  }

  function rgb(a,al){return 'rgba('+(a[0]|0)+','+(a[1]|0)+','+(a[2]|0)+','+(al==null?1:al)+')';}
  function mix(a,b,m){m=Math.max(0,Math.min(1,m));return [a[0]+(b[0]-a[0])*m,a[1]+(b[1]-a[1])*m,a[2]+(b[2]-a[2])*m];}

  return { draw };
}

/* ---------------- Hero ---------------- */
const hero = document.getElementById('coin-hero');
const heroR = makeCoinRenderer(hero, {metal:'gold', denom:'10,000 TOKENS'});
let raf=null, start=performance.now(), paused=false;

function frame(now){
  if(paused) return;
  const t = ((now-start)%4000)/4000;
  heroR.draw(t);
  raf = requestAnimationFrame(frame);
}
function startLoop(){ paused=false; start=performance.now(); raf=requestAnimationFrame(frame); }
startLoop();

window.demo = {
  canvas: hero,
  setTime(t){
    t = ((t%1)+1)%1;
    heroR.draw(t);
  },
  pause(){
    paused = true;
    if(raf) cancelAnimationFrame(raf);
    raf = null;
  }
};

/* ---------------- Editions ---------------- */
document.querySelectorAll('.edition').forEach(el=>{
  const ed = el.getAttribute('data-edition');
  const state = el.getAttribute('data-state');
  const cv = el.querySelector('.edition-canvas');
  const denom = {
    bronze:'10,000 TOKENS', silver:'25,000 TOKENS',
    gold:'100,000 TOKENS', black:'250,000 TOKENS'
  }[ed];
  const r = makeCoinRenderer(cv, {metal:ed, denom});
  // static pose per edition
  const pose = {bronze:0.12, silver:0.30, gold:0.55, black:0.78}[ed];
  r.draw(pose);
  // subtle idle for available
  if(state==='available'){
    let s=performance.now();
    (function anim(now){
      r.draw((pose + ((now-s)%3000)/3000*0.25)%1);
      requestAnimationFrame(anim);
    })(s);
  }
});
</script>
</body>
</html>
